#!/usr/bin/env python3
import os
import pandas as pd
from openai import OpenAI
from dotenv import load_dotenv
import argparse

# Command-line argument parsing
# The input directory should contain the "Top_10_markers_res_X.csv" files generated by the pick_resolution script.
# The output will be a text file with the predicted cell types for each cluster, saved in the specified output directory.
# res is the resolution string (e.g., "RNA_snn_res.0.6") the output of pikc_resolution script.
parser = argparse.ArgumentParser()
parser.add_argument('--input_dir', help="Path to the input marker file")
parser.add_argument('--tissue', help="Type of tissue (e.g., PBMC, brain, etc.)")
parser.add_argument('--species', help="Species (e.g., Human, Mouse)")
parser.add_argument('--out_dir', help="Path where the result should be saved")
args = parser.parse_args()


# Load your .env file
load_dotenv()
client = OpenAI(api_key=os.getenv("OPENAI_API_KEY"))

def annotate_cell_type(markers, species, tissue):
    # Convert list of markers to a comma-separated string
    gene_list = ", ".join(markers)
    
    prompt = f"""
    Identify the most likely cell type for a cluster of {tissue} cells in {species}
    based on the following top 10 marker genes: {gene_list}.
    
    Please follow these rules:
    1. Think step-by-step: briefly explain what cell types each key marker is associated with.
    2. Provide a single 'Final Decision' as the most probable cell type name.
    3. If it is a mixture, suggest the dominant type.
    """

    response = client.chat.completions.create(
        model="gpt-4o-mini", # Use gpt-4o for higher accuracy
        messages=[
            {"role": "system", "content": "You are a professional senior bioinformatician expert in single-cell RNA sequencing."},
            {"role": "user", "content": prompt}
        ],
        temperature=0.1  # Low temperature = more consistent, less "creative" answers
    )
    
    return response.choices[0].message.content


markers_df = pd.read_csv(args.input_dir)
file_name = os.path.basename(args.input_dir).replace(".csv", "")

with open(f"{args.out_dir}/annotated_cell_types{file_name}.txt", 'w') as f:
    for name, group in markers_df.groupby('cluster'):
        print(f"Cluster number: {name}")
        #print(group)

        markers_list = group["gene"].tolist()
        print(f"Markers for cluster {name}: {markers_list}")
        #results = annotate_cell_type(markers_list, args.species, args.tissue)
        results = annotate_cell_type(markers_list, "Human", "PBMC")
        print(f"Predicted cell type for cluster {name}: {results}\n")
        f.write(f"Cluster number: {name}\n")
        f.write(f"Markers for cluster {name}: {markers_list}\n")
        f.write(f"Predicted cell type for cluster {name}: {results}\n\n")
